public class CommandInjectionSecure {

    public static void main(String[] args) {
        String userInput = "example.txt; ls";

        // Validate user input to ensure it does not contain any special characters or commands
        if (!isValidInput(userInput)) {
            System.out.println("Invalid input. Please provide a valid file name.");
            return;
        }

        try {
            Process process = Runtime.getRuntime().exec("cat " + userInput);
            // This code now safely executes "cat example.txt" without additional injected commands
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static boolean isValidInput(String userInput) {
        // Implement your validation logic here, for example, allowing only alphanumeric characters and periods
        return userInput.matches("[a-zA-Z0-9\\.]+");
    }
}

